<?php $conn=new mysqli('localhost','root','','smart_tutor'); $admin_email="blessingsemulyn@gmail.com"; $threshold=3; $sent=[]; foreach(['Form 3','Form 4'] as $class){$res=$conn->query("SELECT subject,topic,COUNT(*) as cnt FROM topic_requests WHERE class_level='$class' GROUP BY subject,topic HAVING cnt>=$threshold"); while($r=$res->fetch_assoc()){$key=$class.$r['subject'].$r['topic']; if(!in_array($key,$sent)){mail($admin_email,"Topic Alert - $class","The topic '{$r['topic']}' in {$r['subject']} has {$r['cnt']} requests.","From:noreply@smarttutor.com"); $sent[]=$key;}}} echo "Notifications sent for ".count($sent)." topics.";?>